{{- /* boolean feature tags */ -}}
{{- $os_id := .chezmoi.os -}}
{{- $is_macos := eq $os_id "darwin" -}}
{{- $hostname := .chezmoi.hostname -}}

{{- /* Identify computer name (Handle macOS ComputerName vs Hostname) */ -}}
{{- $computer_name := $hostname -}}
{{- if $is_macos -}}
{{-   $computer_name = output "scutil" "--get" "ComputerName" | trim -}}
{{- end -}}

{{- /* Machine Classification */ -}}
{{- $is_workstation := eq $computer_name "the-good-machine" -}}
{{- $is_personal_machine := eq $computer_name "the-good-machine" "tiny-tardis" "eressea" -}}
{{- $is_rpi := eq $hostname "grey-havens" -}}

{{- /* Prompts for persistent settings */ -}}
{{- $personal := promptBoolOnce . "personal" "Is this machine personal use and has additional tools?" $is_personal_machine -}}
{{- $email := promptStringOnce . "email" "Your email address" "hussainweb@gmail.com" -}}

{{- /* Software Stack Selection */ -}}
{{- $default_stack := ternary "full" "base" $is_workstation -}}
{{- $stack := promptStringOnce . "stack" "Software stack (base, container, development, full)" $default_stack -}}

{{- /* Derived settings */ -}}
{{- $media := eq $stack "full" -}}
{{- /* ssh_host: true for servers/RPis, false for macOS and known personal workstations */ -}}
{{- $ssh_host := or $is_rpi (not (or $is_macos $is_personal_machine)) -}}

{{- $proxmox_endpoint := "" -}}
{{- if $personal -}}
{{-   $proxmox_endpoint = promptStringOnce . "proxmox_endpoint" "Proxmox API endpoint URL" "https://erebor.husain.me:8006/api2/json" -}}
{{- end -}}
{{- "" -}}

[data]
  personal = {{ $personal }}
  stack = {{ $stack | quote }}
  media = {{ $media }}
  workstation = {{ $is_workstation }}
  macos = {{ $is_macos }}
  rpi = {{ $is_rpi }}
  ssh_host = {{ $ssh_host }}
  email = {{ $email | quote }}
  computerName = {{ $computer_name | quote }}
  proxmox_endpoint = {{ $proxmox_endpoint | quote }}

[hooks.read-source-state.pre]
  command = {{ joinPath .chezmoi.sourceDir ".install-1password.sh" | quote }}

#!/bin/bash

# .chezmoidata/packages.yaml hash: {{ include ".chezmoidata/packages.yaml" | sha256sum }}

# Exit on error
set -e

# Ensure Homebrew is in PATH
if ! command -v brew &> /dev/null; then
    if [ -x /home/linuxbrew/.linuxbrew/bin/brew ]; then
        eval "$(/home/linuxbrew/.linuxbrew/bin/brew shellenv)"
    elif [ -x /opt/homebrew/bin/brew ]; then
        eval "$(/opt/homebrew/bin/brew shellenv)"
    elif [ -x /usr/local/bin/brew ]; then
        eval "$(/usr/local/bin/brew shellenv)"
    fi
fi

# --- Linux APT phase ---
{{ if eq .chezmoi.os "linux" -}}
if command -v apt-get &> /dev/null; then
    echo "Updating and installing APT packages..."
    # sudo apt-get update # Removed for speed, assuming system is up to date
    sudo apt-get install -y {{ range .packages.apt }}{{ . }} {{ end }}
fi
{{- end }}

# --- Homebrew phase (Both macOS and Linux) ---
if command -v brew &> /dev/null; then
    echo "Applying Homebrew bundle..."
    brew bundle --file=/dev/stdin <<EOF
{{ range .packages.taps -}}
tap {{ . | quote }}
{{ end }}

# CLI Tools (Brews)
{{ range .packages.brews.base -}}
brew {{ . | quote }}
{{ end }}

{{ if or (eq .stack "container") (eq .stack "development") (eq .stack "full") -}}
{{ range .packages.brews.container -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if or (eq .stack "development") (eq .stack "full") -}}
{{ range .packages.brews.development -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if .media -}}
{{ range .packages.brews.media -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if or (eq .stack "container") (eq .stack "development") (eq .stack "full") -}}
{{ range .packages.brews.standard_cli -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if eq .chezmoi.os "darwin" -}}
# macOS-specific CLI tools
{{ range .packages.brews.macos -}}
brew {{ . | quote }}
{{ end }}

# CLI Casks
{{ range .packages.casks.cli -}}
cask {{ . | quote }}
{{ end }}

# Fonts
{{ range .packages.casks.fonts -}}
cask {{ . | quote }}
{{ end }}

# Essential macOS GUI apps
{{ range .packages.casks.macos -}}
cask {{ . | quote }}
{{ end }}

{{ if .personal -}}
# Personal/Identity GUI apps
{{ range .packages.casks.personal -}}
cask {{ . | quote }}
{{ end }}
{{- end }}

{{ if or (eq .stack "development") (eq .stack "full") -}}
# Developer GUI apps
{{ range .packages.casks.development -}}
cask {{ . | quote }}
{{ end }}
{{- end }}

{{ if .workstation -}}
# Workstation/Hardware GUI apps
{{ range .packages.casks.workstation -}}
cask {{ . | quote }}
{{ end }}
{{- end }}
{{- end }}
EOF
fi

# --- Linux-specific non-brew phase ---
{{ if eq .chezmoi.os "linux" -}}

# Install NPM tools on Linux development/full stack
{{ if or (eq .stack "development") (eq .stack "full") -}}
if command -v npm &> /dev/null; then
    echo "Installing NPM global packages..."
    {{ range .packages.linux.npm -}}
    # Check if we need sudo for global npm install
    if [ -w "$(npm config get prefix)/lib/node_modules" ] 2>/dev/null || [ -w "$(npm config get prefix)/bin" ] 2>/dev/null; then
        npm install -g {{ . | quote }}
    else
        sudo npm install -g {{ . | quote }}
    fi
    {{ end }}
fi
{{- end }}

# Run custom Linux install scripts
{{ range .packages.linux.scripts -}}
echo "Running custom install script: {{ .name }}..."
{{ .command }}
{{ end }}

{{- end }}

# Custom Tool Initializations
if command -v rtk &> /dev/null; then
    echo "Initializing RTK..."
    {{ range .packages.init.rtk -}}
    {{ . }} || true
    {{ end }}
fi

# Path setup
typeset -U path
path+=("{{ .chezmoi.homeDir }}/.local/bin")
path+=("{{ .chezmoi.homeDir }}/.composer/vendor/bin")

# Set up Homebrew
if [[ -d /opt/homebrew/bin ]]; then
    eval "$(/opt/homebrew/bin/brew shellenv)"
elif [[ -d /home/linuxbrew/.linuxbrew/bin ]]; then
    eval "$(/home/linuxbrew/.linuxbrew/bin/brew shellenv)"
elif [[ -d /usr/local/bin/brew ]]; then
    eval "$(/usr/local/bin/brew shellenv)"
fi

{{ if .personal -}}
path+=("/Users/hw/.antigravity/antigravity/bin")
{{- end }}
export PATH

# Environment variables
export GPG_TTY=$(tty)

{{ if .personal -}}
export HOMEBREW_GITHUB_API_TOKEN={{ onepasswordRead "op://Personal/github.com/Tokens/Homebrew" "my.1password.com" }}
export OPENROUTER_KEY={{ onepasswordRead "op://Employee/a5ay62mcrckiuleljdydlg53su/credential" "axelerant.1password.com" }}
{{- end }}

# LLM Config
{{ if .personal -}}
export OLLAMA_HOST=192.168.50.11
export PM_API_URL={{ .proxmox_endpoint }}
export PM_API_TOKEN_ID=terraform@pve!coder-aule
export PM_API_TOKEN_SECRET={{ onepasswordRead "op://Private/wqeyffrbuhswc3kfd7vjb6q2qa/Tokens/coder-aule" "my.1password.com" }}
export PROXMOX_VE_ENDPOINT={{ .proxmox_endpoint }}
export PROXMOX_VE_API_TOKEN=terraform@pve!coder-aule={{ onepasswordRead "op://Private/wqeyffrbuhswc3kfd7vjb6q2qa/Tokens/coder-aule" "my.1password.com" }}
{{- end }}
export LLM_MODEL=openrouter/google/gemini-2.5-flash-lite

{{ if or (eq .stack "full") (eq .stack "container") -}}
{{   if .personal -}}
export JIRA_API_TOKEN={{ onepasswordRead "op://Employee/n3enjt4hnmrdq7czug6nlkzpti/credential" "axelerant.1password.com" }}
{{-   end }}
{{- end }}

# Basic Zsh settings
fpath=($HOME/.config/zsh/functions $fpath)
autoload -Uz compinit
compinit -i
autoload -Uz lcommit
autoload -Uz update
autoload -Uz emptytrash
autoload -Uz pubkey

HISTFILE=~/.zsh_history
HISTSIZE=10000
SAVEHIST=10000
setopt APPEND_HISTORY
setopt SHARE_HISTORY
setopt HIST_IGNORE_DUPS
setopt HIST_IGNORE_SPACE

# Aliases
{{ range $key, $val := .aliases -}}
alias {{ $key }}='{{ $val }}'
{{ end }}

# Tool initializations
[[ -f ${HOME}/.config/op/plugins.sh ]] && . ${HOME}/.config/op/plugins.sh

# OrbStack initialization
[[ -f {{ .chezmoi.homeDir }}/.orbstack/shell/init2.zsh ]] && . {{ .chezmoi.homeDir }}/.orbstack/shell/init2.zsh 2>/dev/null || :

# Prompts and History Tools
if command -v starship >/dev/null; then
    eval "$(starship init zsh)"
fi

{{ if .personal -}}
if command -v atuin >/dev/null; then
    eval "$(atuin init zsh --disable-up-arrow)"
fi
{{- end }}

# Syntax highlighting and autosuggestions
if [[ -n "$HOMEBREW_PREFIX" ]]; then
  [[ -f "$HOMEBREW_PREFIX/share/zsh-autosuggestions/zsh-autosuggestions.zsh" ]] && source "$HOMEBREW_PREFIX/share/zsh-autosuggestions/zsh-autosuggestions.zsh"
  [[ -f "$HOMEBREW_PREFIX/share/zsh-syntax-highlighting/zsh-syntax-highlighting.zsh" ]] && source "$HOMEBREW_PREFIX/share/zsh-syntax-highlighting/zsh-syntax-highlighting.zsh"

  # zsh-abbr (fish-like abbreviations)
  if [[ -f "$HOMEBREW_PREFIX/share/zsh-abbr/zsh-abbr.zsh" ]]; then
    export ABBR_QUIET=1
    source "$HOMEBREW_PREFIX/share/zsh-abbr/zsh-abbr.zsh"
    # Set up abbreviations from shared data
    {{ range $key, $val := .aliases -}}
    abbr add --session --force {{ $key | quote }}={{ $val | quote }}
    {{ end }}
  fi
fi

fish_add_path -g "{{ .chezmoi.homeDir }}/.local/bin"
fish_add_path -g "{{ .chezmoi.homeDir }}/.composer/vendor/bin"

# Set up Homebrew
if test -d /opt/homebrew/bin
    /opt/homebrew/bin/brew shellenv | source
else if test -d /home/linuxbrew/.linuxbrew/bin
    /home/linuxbrew/.linuxbrew/bin/brew shellenv | source
else if test -d /usr/local/bin
    if test -f /usr/local/bin/brew
        /usr/local/bin/brew shellenv | source
    end
end

set -x GPG_TTY (tty)
set -x fish_emoji_width 2

{{ if .personal -}}
set -gx HOMEBREW_GITHUB_API_TOKEN {{ onepasswordRead "op://Personal/github.com/Tokens/Homebrew" "my.1password.com" }}
set -gx OPENROUTER_KEY {{ onepasswordRead "op://Employee/a5ay62mcrckiuleljdydlg53su/credential" "axelerant.1password.com" }}
{{- end }}

{{ if or (eq .stack "full") (eq .stack "container") -}}
{{   if .personal -}}
set -gx JIRA_API_TOKEN {{ onepasswordRead "op://Employee/n3enjt4hnmrdq7czug6nlkzpti/credential" "axelerant.1password.com" }}
{{-   end }}
{{- end }}

test -e {$HOME}/.config/op/plugins.sh ; and source {$HOME}/.config/op/plugins.sh

# Added by OrbStack: command-line tools and integration
# This won't be added again if you remove it.
test -e {{ .chezmoi.homeDir }}/.orbstack/shell/init2.fish ; and source ~/.orbstack/shell/init2.fish 2>/dev/null || :

starship init fish | source

{{ if .personal -}}
# Added by Antigravity
fish_add_path /Users/hw/.antigravity/antigravity/bin
{{- end }}

{{ if .personal -}}
atuin init fish --disable-up-arrow | source
{{- end }}

{{ range $key, $val := .aliases -}}
abbr {{ $key | quote }} {{ $val | quote }}
{{ end }}

